import{c as t,Q as o,j as d,m as i}from"./chunks/framework.Bhbi9jCp.js";const S=JSON.parse('{"title":"苹果原生开发系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"iosNativeLearning/00-写作计划.md","filePath":"iosNativeLearning/00-写作计划.md","lastUpdated":1779613419000}'),c={name:"iosNativeLearning/00-写作计划.md"};function n(a,e,s,r,l,p){return o(),d("div",null,[...e[0]||(e[0]=[i(`<h1 id="苹果原生开发系列写作计划" tabindex="-1">苹果原生开发系列写作计划 <a class="header-anchor" href="#苹果原生开发系列写作计划" aria-label="Permalink to &quot;苹果原生开发系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第六类「平台原生开发」之 P 项 iosNative,⭐⭐⭐。 本系列基线版本为 <strong>iOS 18 / Swift 6 / Xcode 16 / SwiftUI</strong>(截稿前以 <strong>2026-05 时点的最新 minor / patch 版本</strong>为参照;iOS 19 已正式发布,会在涉及新 API 的篇目里单独标注「iOS 19+」,主线仍以 iOS 18 为最低部署目标,避免文章漂移)。 本系列不做&quot;Objective-C + Storyboard 老 iOS 复刻&quot;,也不做&quot;SwiftUI 控件展览&quot;,而是围绕一个可演进的 iOS 应用原型,逐层拆解 Swift 心智、声明式 UI、Apple 平台能力、性能工程与 App Store 发布通路。</p></blockquote><hr><h2 id="核心定位" tabindex="-1">核心定位 <a class="header-anchor" href="#核心定位" aria-label="Permalink to &quot;核心定位&quot;">​</a></h2><p>这不是&quot;iOS 全家桶百科&quot;,也不是&quot;Swift 语法手册&quot;,更不是&quot;Flutter 转 iOS 速成&quot;。本系列只解决一个明确目标:</p><blockquote><p>让一个熟悉编程但不熟悉 Apple 平台的人,能用 Swift 6 + SwiftUI + iOS 18 做出一款结构清楚、数据可持久化、能调用系统能力、能通过审核上架 TestFlight / App Store 的原生 iOS 应用。</p></blockquote><p>因此本系列默认选择:</p><table tabindex="0"><thead><tr><th>维度</th><th>选择</th><th>原因</th></tr></thead><tbody><tr><td>系统基线</td><td>iOS 18 (最低部署目标),兼顾 iOS 19+ 新 API</td><td>覆盖 2026 主流装机量,避免追新尾巴上的 beta API</td></tr><tr><td>工具链</td><td>Xcode 16 / Swift 6 toolchain</td><td>Swift 6 严格并发与 macro 已稳定,Xcode 16 是首批默认</td></tr><tr><td>主语言</td><td><strong>Swift 6</strong>,严格并发模式 (<code>SwiftSettings.swiftLanguageMode(.v6)</code>)</td><td>编译期消灭数据竞争,贴近 Apple 官方未来方向</td></tr><tr><td>UI 主线</td><td><strong>SwiftUI</strong> 声明式 UI + <code>@Observable</code> 状态</td><td>Apple 全平台默认 UI 框架,不再讲 Storyboard / XIB / 传统 ViewController</td></tr><tr><td>并发模型</td><td>Swift Concurrency(<code>async/await</code> / <code>actor</code> / <code>Sendable</code> / <code>Task</code>)</td><td>GCD / RunLoop 仅作对比心智,不写老式教程</td></tr><tr><td>数据层</td><td><strong>SwiftData</strong> 优先,Core Data 仅在必要场景作为后备</td><td>iOS 17+ 推荐路径,基于 Core Data 但 API 现代化</td></tr><tr><td>跨端</td><td><strong>不覆盖</strong>,由 <code>flutterLearning</code> 负责跨端表现层</td><td>本系列只讲 Apple 平台原生能力</td></tr><tr><td>兄弟平台</td><td>macOS / iPadOS / visionOS / watchOS 仅在尾段简提</td><td>主线聚焦 iPhone,避免目标分散</td></tr><tr><td>文章目标</td><td>机制 + 工程取舍 + 可运行示例</td><td>不只贴 API,要讲为什么 Apple 这样设计、何时不要这样写</td></tr></tbody></table><p>读者画像:</p><ul><li>已经写过其他语言/框架的应用(Flutter / React Native / Android / Web),想真正用「Apple 原生方式」做 iOS。</li><li>看得懂英文 API 文档,但被 Swift Concurrency、<code>@Observable</code>、SwiftData、严格并发的取舍劝退过。</li><li>想做的是一款能上 App Store 的真应用,而不是 Playground 玩具或某个 SDK 的 demo。</li></ul><hr><h2 id="swift-6-ios-18-swiftui-关键新特性与本系列定位" tabindex="-1">Swift 6 / iOS 18 / SwiftUI 关键新特性与本系列定位 <a class="header-anchor" href="#swift-6-ios-18-swiftui-关键新特性与本系列定位" aria-label="Permalink to &quot;Swift 6 / iOS 18 / SwiftUI 关键新特性与本系列定位&quot;">​</a></h2><p>Swift 6.0 于 2024-09 随 Xcode 16 发布;到 2026-05,Swift 6.x 已经经过若干 minor 版本迭代,iOS 19 也已发布。本系列把下列变更显式纳入相关篇目,避免读者把 Swift 5 / iOS 16 / 旧 SwiftUI 心智带进 2026 的项目模板:</p><table tabindex="0"><thead><tr><th>变更</th><th>影响范围</th><th>本系列在哪篇展开</th></tr></thead><tbody><tr><td><strong>Swift 6 严格并发(strict concurrency by default)</strong></td><td>数据竞争编译期报错;<code>Sendable</code> / actor 隔离传染整张依赖图</td><td>第 04 / 05 篇心智段,第 26 / 27 篇排障</td></tr><tr><td><strong><code>@Observable</code> 宏 + Observation 框架</strong></td><td>替代 <code>ObservableObject</code> + <code>@Published</code>;视图自动追踪字段而非整对象</td><td>第 07 篇主篇,第 08 / 13 / 26 篇</td></tr><tr><td><strong><code>@Entry</code> 宏(iOS 18 新)</strong></td><td><code>EnvironmentValues</code> 自定义键从 30 行样板减为 1 行</td><td>第 08 篇环境值章节</td></tr><tr><td><strong>SwiftData 稳定化 + CloudKit 自动同步</strong></td><td><code>@Model</code> / <code>ModelContainer</code> / <code>@Query</code> 取代手写 Core Data;<code>@Model</code> 可直接对接 iCloud</td><td>第 14 篇主线</td></tr><tr><td><strong>NavigationStack + 类型化路由(iOS 16+,18 完善)</strong></td><td><code>NavigationLink(value:)</code> + <code>.navigationDestination(for:)</code> 取代 <code>NavigationView</code></td><td>第 13 篇</td></tr><tr><td><strong>SwiftUI 动画 / 转场 / <code>matchedGeometryEffect</code> / <code>TimelineView</code></strong></td><td>显式动画与隐式动画分离,共享元素过渡有原生 API</td><td>第 11 篇</td></tr><tr><td><strong>SwiftUI Gesture 组合(<code>SimultaneousGesture</code> / <code>ExclusiveGesture</code> / <code>HighPriorityGesture</code>)</strong></td><td>手势冲突与优先级在声明式 UI 下重新组织</td><td>第 12 篇</td></tr><tr><td><strong>WidgetKit / ActivityKit / Dynamic Island(iOS 16.1+ / 17 稳定)</strong></td><td>Widget / Live Activities / Dynamic Island 同一套 SwiftUI 子集</td><td>第 22 篇</td></tr><tr><td><strong>StoreKit 2(iOS 15+,Swift 原生)</strong></td><td><code>Product</code> / <code>Transaction.updates</code> 取代旧 <code>SKPaymentQueue</code>;JWS 收据本地校验</td><td>第 23 篇</td></tr><tr><td><strong>Localizable.xcstrings 字符串目录(Xcode 15+)</strong></td><td>取代旧 <code>Localizable.strings</code>,翻译状态可视化</td><td>第 24 篇</td></tr><tr><td><strong>Core ML / Vision / Apple Intelligence on-device</strong></td><td>端侧推理 + Vision Framework 视觉任务统一入口;A17/M 系列上有 ANE 加速</td><td>第 25 篇</td></tr><tr><td><strong>Swift Testing 框架(<code>import Testing</code>)</strong></td><td><code>@Test</code> / <code>#expect</code> / <code>#require</code> 取代 XCTest 大部分场景,但 UI Testing 仍走 XCTest</td><td>第 29 篇</td></tr><tr><td><strong>Privacy Manifests (<code>PrivacyInfo.xcprivacy</code>) 上架强制要求</strong></td><td>第三方 SDK 与自家代码都需要声明 API reason / 数据使用</td><td>第 20 / 30 篇</td></tr><tr><td><strong>SwiftUI 性能调优 API</strong>(<code>_printChanges</code>、<code>@Observable</code> diff 行为)</td><td>重渲染追踪心智不同于 React;Combine 仅在桥接处保留</td><td>第 26 篇</td></tr><tr><td><strong>背景任务 BGTaskScheduler + BGProcessingTask</strong></td><td>取代旧的后台 fetch 心智</td><td>第 21 篇</td></tr><tr><td><strong>App Intents(iOS 16+)</strong></td><td>与系统集成的统一入口(Shortcuts / Spotlight / Widgets / Siri)</td><td>第 21 / 22 篇</td></tr><tr><td><strong><code>URLSession</code> 全面 async / <code>bytes(for:)</code> 流式 API</strong></td><td>不再写 <code>dataTask</code> 回调链;Combine 仅在桥接处保留</td><td>第 15 篇</td></tr><tr><td><strong>MetricKit <code>MXMetricPayload</code> + <code>OSLogStore</code> 检索</strong></td><td>线上 Crash 与性能指标统一上报</td><td>第 27 篇</td></tr></tbody></table><blockquote><p>注:iOS 19 引入的 Liquid Glass 等视觉系统变化、新交互组件仅在涉及具体 API 时单独标注「iOS 19+」并给降级方案;本系列正篇仍以 iOS 18 为最低部署目标,与 App Store 主流装机量对齐。</p></blockquote><hr><h2 id="七层路线" tabindex="-1">七层路线 <a class="header-anchor" href="#七层路线" aria-label="Permalink to &quot;七层路线&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swift 心智与项目骨架</span></span>
<span class="line"><span>   → SwiftUI 声明式 UI 与状态模型</span></span>
<span class="line"><span>   → 动画、手势与导航</span></span>
<span class="line"><span>   → 数据、网络与本地存储闭环</span></span>
<span class="line"><span>   → 系统能力、UIKit 互操作与权限</span></span>
<span class="line"><span>   → Widget / 商业化 / 智能化 / 辅助功能</span></span>
<span class="line"><span>   → 性能、测试、发布与 Apple 生态</span></span></code></pre></div><p>核心节奏是:<strong>前 15 篇先把&quot;心智 + UI + 闭环&quot;跑通,后 15 篇补系统能力、Widget / Live Activities、StoreKit 2、Core ML、性能与发布通路。</strong></p><hr><h2 id="篇目设计-30-篇" tabindex="-1">篇目设计 (30 篇) <a class="header-anchor" href="#篇目设计-30-篇" aria-label="Permalink to &quot;篇目设计 (30 篇)&quot;">​</a></h2><h3 id="第一层-swift-心智与项目骨架-01-05" tabindex="-1">第一层:Swift 心智与项目骨架 (01-05) <a class="header-anchor" href="#第一层-swift-心智与项目骨架-01-05" aria-label="Permalink to &quot;第一层:Swift 心智与项目骨架 (01-05)&quot;">​</a></h3><ul><li><strong>01 Swift 6 / iOS 18 / SwiftUI 心智总览</strong> (为什么选原生 / Apple SDK 分层 / <code>App</code> 协议入口 / 本系列最终会做出什么 / iOS 18 与 iOS 19 部署目标取舍)</li><li><strong>02 Xcode 16 项目结构、Bundle、Info.plist 与 <code>xcconfig</code></strong> (<code>Project</code> vs <code>Workspace</code> / Scheme 与 Build Configuration / <code>Info.plist</code> 现代化 generated 模式 / <code>xcconfig</code> 分环境配置 / Asset Catalog 与 SF Symbols)</li><li><strong>03 Swift 6 类型系统:值类型 / 引用类型 / 协议 / 泛型</strong> (<code>struct</code> 与 <code>class</code> 内存语义 / <code>protocol</code> + <code>associatedtype</code> / opaque return <code>some View</code> / <code>any</code> existential / 与 Dart/Kotlin 类型系统对照)</li><li><strong>04 Swift Concurrency 心智:<code>async/await</code> / <code>Task</code> / 结构化并发</strong> (<code>Task</code> / <code>TaskGroup</code> / <code>async let</code> / 取消传播 / <code>MainActor</code> / GCD 仅作对比,不再用 <code>DispatchQueue.async</code> 教学)</li><li><strong>05 <code>actor</code> / <code>Sendable</code> / 严格并发:Swift 6 数据竞争编译期消除</strong> (<code>actor</code> 隔离 / <code>nonisolated</code> / <code>Sendable</code> 协议 / <code>@unchecked Sendable</code> 红线 / <code>@MainActor</code> 类型与方法标注 / 与 Rust <code>Send/Sync</code> 对照)</li></ul><h3 id="第二层-swiftui-声明式-ui-与状态模型-06-10" tabindex="-1">第二层:SwiftUI 声明式 UI 与状态模型 (06-10) <a class="header-anchor" href="#第二层-swiftui-声明式-ui-与状态模型-06-10" aria-label="Permalink to &quot;第二层:SwiftUI 声明式 UI 与状态模型 (06-10)&quot;">​</a></h3><ul><li><strong>06 SwiftUI <code>View</code> 协议、声明式渲染与 <code>@State</code></strong> (<code>body: some View</code> / 视图是值类型 / SwiftUI 重计算 vs 重渲染 / <code>@State</code> 仅用于视图私有可变状态 / 与 React useState 对照心智)</li><li><strong>07 <code>@Observable</code> / Observation 框架与状态共享</strong> (<code>@Observable</code> 宏展开 / 字段级追踪 / <code>@Bindable</code> / 取代 <code>ObservableObject</code> + <code>@Published</code> / 与 MVVM 心智落地)</li><li><strong>08 <code>@Binding</code> / <code>@Environment</code> / <code>@Entry</code> 与数据流向</strong> (<code>@Binding</code> 双向绑定 / <code>EnvironmentValues</code> / <strong>iOS 18 <code>@Entry</code> 宏简化自定义环境键</strong> / 何时用 environment 而不是 prop drilling)</li><li><strong>09 SwiftUI 布局系统:<code>HStack</code> / <code>VStack</code> / <code>ZStack</code> / <code>Grid</code> / <code>Layout</code> 协议</strong> (布局协议 / proposal-response 心智 / <code>LazyVStack</code> 与可见性 / <code>Layout</code> 自定义协议入门 / 与 Flutter Flex / Web Flex 对照)</li><li><strong>10 Modifier 链、<code>ViewModifier</code> 自定义与样式系统(<code>ButtonStyle</code> / <code>LabelStyle</code>)</strong> (Modifier 顺序敏感 / 自定义 <code>ViewModifier</code> / <code>ButtonStyle</code> / <code>PrimitiveButtonStyle</code> / 样式与逻辑解耦)</li></ul><h3 id="第三层-动画、手势与导航-11-13" tabindex="-1">第三层:动画、手势与导航 (11-13) <a class="header-anchor" href="#第三层-动画、手势与导航-11-13" aria-label="Permalink to &quot;第三层:动画、手势与导航 (11-13)&quot;">​</a></h3><ul><li><strong>11 SwiftUI 动画与转场:<code>withAnimation</code> / <code>matchedGeometryEffect</code> / <code>TimelineView</code> / <code>PhaseAnimator</code></strong> (隐式动画 vs 显式动画 / <code>Animation.spring/easeInOut/interpolatingSpring</code> / <code>transaction</code> 控制 / <code>matchedGeometryEffect</code> 共享元素 / <code>TimelineView</code> 时间驱动动画 / <code>PhaseAnimator</code> (iOS 17+) / 与 UIKit <code>UIView.animate</code> 心智对照 / 动画与重渲染成本边界)</li><li><strong>12 SwiftUI 手势系统:<code>Gesture</code> / 组合 / 优先级与冲突</strong> (<code>TapGesture</code> / <code>LongPressGesture</code> / <code>DragGesture</code> / <code>MagnifyGesture</code> / <code>RotateGesture</code> / <code>SimultaneousGesture</code> / <code>ExclusiveGesture</code> / <code>HighPriorityGesture</code> / 手势状态 <code>@GestureState</code> / 与 <code>ScrollView</code> / <code>NavigationStack</code> 滑动返回的冲突 / <code>onScrollGeometryChange</code> (iOS 18+))</li><li><strong>13 <code>NavigationStack</code> 与类型化路由</strong> (<code>NavigationStack(path:)</code> / <code>NavigationLink(value:)</code> / <code>.navigationDestination(for:)</code> / <code>NavigationSplitView</code> for iPad / 弃用的 <code>NavigationView</code> / 路由状态可恢复 / Deep Link 与 <code>onOpenURL</code> 桥接)</li></ul><h3 id="第四层-数据、网络与本地存储闭环-14-16" tabindex="-1">第四层:数据、网络与本地存储闭环 (14-16) <a class="header-anchor" href="#第四层-数据、网络与本地存储闭环-14-16" aria-label="Permalink to &quot;第四层:数据、网络与本地存储闭环 (14-16)&quot;">​</a></h3><blockquote><p>本层每篇做&quot;最小可行&quot;,目标是让原型能&quot;列表 → 详情 → 编辑 → 持久化 → 同步&quot;跑通;深度优化与系统能力留到后面层。</p></blockquote><ul><li><strong>14 SwiftData 全景:<code>@Model</code> / <code>ModelContainer</code> / <code>@Query</code> / Schema 迁移 / CloudKit 同步</strong> (<code>@Model</code> 宏 / 关系建模 / <code>ModelContainer</code> 与 SwiftUI <code>App</code> 注入 / <code>@Query</code> 在视图里订阅 / <code>VersionedSchema</code> + <code>MigrationPlan</code> 迁移 / 复杂查询 fallback 到 NSPredicate / 何时仍要直接用 Core Data / <code>@Model</code> + CloudKit 自动同步 / 与 Realm / Room 心智对照)</li><li><strong>15 <code>URLSession</code> async API、<code>Codable</code> 与网络层架构(含 Combine 桥接)</strong> (<code>URLSession.shared.data(for:)</code> / <code>URLSession.bytes(for:)</code> 流式 / <code>JSONEncoder/Decoder</code> 与 key strategy / 错误模型 <code>URLError</code> / 拦截器(adapter)模式 / Retry / 与 actor 配合的请求队列 / Combine 何时仍胜出:<code>Notification</code> / Timer / Foundation 接口桥接 / <code>@Published</code> vs <code>@Observable</code> / 不为了 Combine 而 Combine)</li><li><strong>16 Keychain、数据加密与 App Group 共享存储</strong> (<code>Keychain Services</code> API / <code>kSecAttrAccessible*</code> 访问控制 / <code>SecItemAdd/Copy/Update/Delete</code> 五要素 / iCloud Keychain 同步 / <code>CryptoKit</code> 对称 / 非对称 / 哈希常见用法 / <code>App Group</code> 容器与 <code>UserDefaults(suiteName:)</code> / 与 Widget / Extension 共享数据)</li></ul><h3 id="第五层-系统能力、uikit-互操作与权限-17-21" tabindex="-1">第五层:系统能力、UIKit 互操作与权限 (17-21) <a class="header-anchor" href="#第五层-系统能力、uikit-互操作与权限-17-21" aria-label="Permalink to &quot;第五层:系统能力、UIKit 互操作与权限 (17-21)&quot;">​</a></h3><ul><li><strong>17 SwiftUI / UIKit / Objective-C 互操作</strong> (<code>UIViewRepresentable</code> 五要素 / <code>UIViewControllerRepresentable</code> / <code>Coordinator</code> 桥接 delegate / <code>UIHostingController</code> 嵌入 UIKit 容器 / SwiftUI 不存在的能力清单 / Bridging Header / <code>@objc</code> / <code>@objcMembers</code> / OC 类暴露给 Swift 的可空性标注 / <strong>本系列唯一一篇直面 UIKit 与 OC 的篇目</strong>,只为兼容旧 SDK / KVO / NSException)</li><li><strong>18 推送:<code>UNUserNotificationCenter</code> + APNs</strong> (<code>UNUserNotificationCenter.requestAuthorization</code> / <code>UNNotificationContent</code> / 本地通知 vs 远程推送 / APNs token 上行 / Notification Service / Content Extension / 静默推送与后台唤醒 / Push to Start Live Activity (iOS 17.2+))</li><li><strong>19 AVFoundation 与 PhotoKit:相机、播放与相册访问</strong> (<code>AVCaptureSession</code> / <code>AVPlayer</code> / <code>AVPlayerLayer</code> 在 SwiftUI 里的承载 / <code>PHPhotoLibrary</code> 权限分级(<code>addOnly</code> vs <code>readWrite</code>)/ <code>PhotosPicker</code>(系统级选择器,无需相册权限)/ <code>AVAudioRecorder</code> 录音)</li><li><strong>20 权限模型与 Privacy Manifest(<code>PrivacyInfo.xcprivacy</code>)</strong> (权限弹窗 lifecycle / <code>Info.plist</code> usage description 必填项 / <strong>2024 起 Apple 强制要求 Privacy Manifest</strong> / 第三方 SDK Privacy Manifest 校验 / Required Reason API 清单 / Tracking 与 IDFA / ATT 弹窗时机)</li><li><strong>21 后台模式、<code>BGTaskScheduler</code> 与 App Intents 入口</strong> (<code>UIApplication</code> 五种后台模式 / <code>BGAppRefreshTask</code> / <code>BGProcessingTask</code> 调度策略 / 静默推送唤醒边界 / <strong>App Intents 完整心智</strong>:<code>AppIntent</code> 协议 / <code>AppShortcut</code> / <code>IntentParameter</code> / 与 Shortcuts / Spotlight / Widget / Siri 的统一入口)</li></ul><h3 id="第六层-widget-商业化-智能化-辅助功能-22-25" tabindex="-1">第六层:Widget / 商业化 / 智能化 / 辅助功能 (22-25) <a class="header-anchor" href="#第六层-widget-商业化-智能化-辅助功能-22-25" aria-label="Permalink to &quot;第六层:Widget / 商业化 / 智能化 / 辅助功能 (22-25)&quot;">​</a></h3><ul><li><strong>22 WidgetKit + ActivityKit:Widget / Live Activities / Dynamic Island</strong> (<code>Widget</code> 协议 / <code>TimelineProvider</code> / <code>TimelineEntry</code> / Reload 策略 / <code>WidgetFamily</code> 尺寸 / <strong>Interactive Widget (iOS 17+) 通过 App Intent 处理交互</strong> / <code>ActivityAttributes</code> + <code>ActivityKit</code> 启动 Live Activity / Dynamic Island 三态 UI:<code>compactLeading</code> / <code>compactTrailing</code> / <code>expanded</code> / <code>minimal</code> / ActivityKit push token 与远程更新)</li><li><strong>23 StoreKit 2:内购 / 订阅 / Sign in with Apple</strong> (<code>Product</code> / <code>Product.products(for:)</code> / <code>Transaction.updates</code> AsyncSequence / <code>Product.purchase()</code> / <code>Transaction.currentEntitlements</code> / JWS 签名收据本地校验 / 沙盒测试 / 订阅状态续费心智 / App Store Server Notifications V2 / <code>AuthenticationServices</code> <code>SignInWithAppleButton</code> / <code>ASAuthorizationAppleIDCredential</code> / Sign in with Apple 服务端 token 校验)</li><li><strong>24 Accessibility 与国际化(<code>Localizable.xcstrings</code>)</strong> (<code>accessibilityLabel</code> / <code>accessibilityHint</code> / <code>accessibilityValue</code> / <code>accessibilityElement(children:)</code> / Dynamic Type <code>Font.body</code> 缩放 / VoiceOver 自检清单 / Reduce Motion / High Contrast 适配 / <strong>Xcode 15+ String Catalog (<code>.xcstrings</code>)</strong> 取代 <code>Localizable.strings</code> / 翻译状态可视化 / 复数 / 设备类型变体 / <code>String(localized:)</code> 与 <code>LocalizedStringResource</code>)</li><li><strong>25 Core ML / Vision / Apple Intelligence:on-device AI</strong> (<code>Vision Framework</code>:<code>VNRecognizeTextRequest</code> / <code>VNDetectFaceRectanglesRequest</code> / <code>VNCoreMLRequest</code> / Core ML 模型导入 <code>.mlmodel</code> / <code>.mlpackage</code> / <code>MLModelConfiguration.computeUnits</code> 选择 CPU / GPU / ANE / Core ML Stable Diffusion 心智 / <code>CreateML</code> 训练入门 / MLX 框架(Apple Silicon 上的 PyTorch-like) / Apple Intelligence 入口与隐私边界)</li></ul><h3 id="第七层-性能、测试与发布-26-30" tabindex="-1">第七层:性能、测试与发布 (26-30) <a class="header-anchor" href="#第七层-性能、测试与发布-26-30" aria-label="Permalink to &quot;第七层:性能、测试与发布 (26-30)&quot;">​</a></h3><ul><li><strong>26 SwiftUI 性能:重渲染追踪、<code>_printChanges</code> 与列表优化</strong> (SwiftUI 重计算 vs UIKit 重渲染 / <code>Self._printChanges()</code> / <code>equatable</code> 视图 / <code>LazyVStack</code> / <code>id(_:)</code> 滥用代价 / 不必要的 <code>@State</code> 触发链 / <code>@Observable</code> 字段级追踪带来的性能赢面)</li><li><strong>27 Instruments 实战 + MetricKit + Crash 线上诊断</strong> (Instruments 模板选型 / Time Profiler 火焰图读法 / Allocations 与 retain cycle / Leaks 局限 / SwiftUI Instruments 模板 / <code>.crash</code> 与 <code>.ips</code> 符号化 / <code>dSYM</code> / Xcode Organizer / <code>MetricKit</code> <code>MXMetricPayload</code> 自动上报 / <code>os_log</code> / <code>OSLogStore</code> 检索 / 真机 vs 模拟器测试边界)</li><li><strong>28 Swift Package Manager、模块化与 Xcode Build System</strong> (<code>Package.swift</code> / target / product / <code>.binaryTarget</code> xcframework / Resource bundle / 私有仓库 SPM / 模块化拆分原则 / SwiftSettings 启用严格并发 / Build System 阶段 / Linker / <code>xcconfig</code> 多环境配置 / <code>User-Defined</code> settings / <code>OTHER_SWIFT_FLAGS</code> / Build for testing / Archive 流程)</li><li><strong>29 测试体系:XCTest + Swift Testing + Preview + UI Testing</strong> (XCTest 仍负责 UI Test / Performance Test / <code>import Testing</code> 新框架 <code>@Test</code> / <code>#expect</code> / <code>#require</code> / 参数化测试 / async 测试 / 测试 SwiftData 与 <code>MainActor</code> / <code>#Preview</code> 宏 / Preview 与真实 App 运行环境差异 / <code>XCUIApplication</code> UI Test / Accessibility identifier 设计 / 自建 snapshot 测试(<code>swift-snapshot-testing</code>)/ CI 跑 UI Test 的代价)</li><li><strong>30 App Store Connect、TestFlight、签名链与审核 + macOS / iPadOS / visionOS 延伸</strong> (<code>Apple Developer</code> 角色 / Bundle ID / Certificate / Provisioning Profile / Automatic vs Manual signing / TestFlight 内部 vs 外部测试 / Build 上传与 ASC API / 加密合规声明 / 审核常见 reject 类型 / 隐私问询表单 / Sandboxing / 多设备适配清单 / Catalyst 与 SwiftUI 跨 Apple 平台共享代码 / visionOS / watchOS 心智延伸 / 发售前最后清单)</li></ul><hr><h2 id="贯穿项目" tabindex="-1">贯穿项目 <a class="header-anchor" href="#贯穿项目" aria-label="Permalink to &quot;贯穿项目&quot;">​</a></h2><p>全系列使用同一个逐步演进的 iOS 应用原型,工程目录约定放在 <code>iosNativeLearning/demo/</code>,主题是「<strong>一款本地优先 + iCloud 同步 + 可推送 + 能录入图片与音频笔记的个人记录类 App</strong>」(中文叫「写日记」一类形态,英文 working title <code>NotesIsland</code>)。</p><p><strong>例外</strong>:第 17 篇(UIKit / Objective-C 互操作)允许独立最小工程演示老 SDK 桥接;第 28 篇(SPM 模块化)允许引用拆分后的多模块工程;第 30 篇延伸的 visionOS / watchOS 部分允许引用另一个最小 Multiplatform 工程。</p><table tabindex="0"><thead><tr><th>阶段</th><th>原型状态</th><th>验收标准</th></tr></thead><tbody><tr><td>01-05</td><td>空工程骨架</td><td>Xcode 16 项目可启动;基础目录、<code>xcconfig</code>、Swift 6 模式都已就位</td></tr><tr><td>06-10</td><td>可见的本地 UI</td><td>有列表、有详情、有表单输入;<code>@Observable</code> 状态闭环跑通</td></tr><tr><td>11-13</td><td>动画与交互完整</td><td>隐式 / 显式动画 / 共享元素过渡完整;手势组合无冲突;NavigationStack 可深链</td></tr><tr><td>14-16</td><td>数据闭环</td><td>SwiftData 持久化 + 网络拉数据 + Keychain 凭据安全;数据丢失/迁移可控</td></tr><tr><td>17-21</td><td>系统能力</td><td>UIKit 互操作 / 推送 / 拍照与选图 / 权限合规 / BGTaskScheduler + App Intents</td></tr><tr><td>22-25</td><td>Widget / 商业化 / 智能化 / 辅助功能</td><td>Widget + Live Activities 上线;StoreKit 2 内购 + Sign in with Apple 跑通;VoiceOver / 多语言验收;Vision / Core ML 端侧推理示例</td></tr><tr><td>26-30</td><td>可发布</td><td>性能可量化 + Instruments / MetricKit 上报 + SPM 模块化 + Swift Testing 覆盖 + TestFlight 内测 + Privacy Manifest 通过 + 商店审核检查表过关</td></tr></tbody></table><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>跨端 UI、Dart 语言、状态管理三件套</td><td>flutterLearning</td><td>不重复跨端心智,讲 Apple 平台原生能力与 Swift / SwiftUI</td></tr><tr><td>协程与异步、并发数据竞争</td><td>rustLearning / goLearning / osLearning</td><td>不讲并发理论,只讲 Swift Concurrency 在 Apple 平台落地与 <code>actor</code> / <code>Sendable</code> 工程取舍</td></tr><tr><td>HTTP / TLS / WebSocket 协议细节</td><td>networkLearning</td><td>不重复协议栈,只讲 <code>URLSession</code> async API、拦截器、错误模型与权限 ATS</td></tr><tr><td>AI / on-device ML 模型本身</td><td>aiLearning / aiInfraLearning</td><td>不重复模型,只在第 25 篇讲 Core ML / Vision / MLX / Apple Intelligence 的落地点</td></tr><tr><td>数据建模、ER 设计、SQL 调优</td><td>backendLearning / dataEngineering</td><td>不重复 SQL,只讲 SwiftData / Core Data + CloudKit 的本地优先建模</td></tr><tr><td>OWASP / 移动端逆向 / 越狱与安全</td><td>securityLearning</td><td>不重复攻防,只讲 ATS / Keychain / App Transport Security / 越狱检测的工程边界</td></tr><tr><td>向量、矩阵、信号处理数学</td><td>mathForCS</td><td>只讲在 AVFoundation / Metal / Core Animation 用得到的工程化函数</td></tr><tr><td>设计模式与架构选型</td><td>designPatternLearning / systemDesign</td><td>只讲 MV(VM) / TCA 心智 + SwiftUI 数据流在原生场景的取舍,不重复模式定义</td></tr><tr><td>Git / 大仓库 / 多人协作</td><td>gitLearning</td><td>不重复 Git,只在 SPM 私有源、Xcode 项目冲突合并那段给踩坑</td></tr><tr><td>CI/CD、可观测、SRE</td><td>devopsLearning</td><td>不重复 CI,只讲 Xcode Cloud / Fastlane / TestFlight 自动分发的最小骨架</td></tr></tbody></table><hr><h2 id="单篇写作模板" tabindex="-1">单篇写作模板 <a class="header-anchor" href="#单篇写作模板" aria-label="Permalink to &quot;单篇写作模板&quot;">​</a></h2><p>每篇遵循固定结构,避免变成 API 散点:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 机制定位</span></span>
<span class="line"><span>   - 这个机制在 iOS 应用里解决什么核心问题</span></span>
<span class="line"><span>   - 用 UIKit / 老 SwiftUI / 跨端框架的同类做法会遇到什么坑</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Apple 平台心智</span></span>
<span class="line"><span>   - 对应核心类 / 协议 / 宏(给出类名与 framework,如 \`URLSession\` in Foundation,\`@Model\` in SwiftData)</span></span>
<span class="line"><span>   - 生命周期、隔离域(MainActor / actor / nonisolated)、数据流向</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 工程实现</span></span>
<span class="line"><span>   - 30-150 行可运行 Swift 6 代码,标注 \`// MARK:\` 段落</span></span>
<span class="line"><span>   - 严格并发模式下能通过编译,无 \`@unchecked Sendable\`</span></span>
<span class="line"><span>   - 指明文件归属(\`Features/Notes/NoteListView.swift\` 等)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 调参与验收</span></span>
<span class="line"><span>   - 哪些参数影响性能 / 用户体验 / 审核通过率</span></span>
<span class="line"><span>   - 真机 vs 模拟器差异</span></span>
<span class="line"><span>   - 如何验证这一篇完成了(单步操作清单 + 期望结果)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 踩坑</span></span>
<span class="line"><span>   - Swift 6 / iOS 18 下的常见坑</span></span>
<span class="line"><span>   - 与 Swift 5 / iOS 16 旧教程、Stack Overflow 老答案的差异</span></span>
<span class="line"><span>   - 跨 iOS 版本兼容(\`if #available\`)的最低成本写法</span></span></code></pre></div><hr><h2 id="交付标准" tabindex="-1">交付标准 <a class="header-anchor" href="#交付标准" aria-label="Permalink to &quot;交付标准&quot;">​</a></h2><p>不是每篇都重建工程,而是维护一个贯穿式示例项目,并在关键机制处提供最小复现 Snippet。</p><table tabindex="0"><thead><tr><th>交付物</th><th>要求</th></tr></thead><tbody><tr><td>Markdown 正文</td><td>讲清机制、Apple 平台取舍、实现步骤、踩坑边界,字数控制在 5k-9k 中文</td></tr><tr><td>示例项目</td><td><code>iosNativeLearning/demo/</code> 中维护同一个可运行 Xcode 16 工程,Swift 6 严格并发模式</td></tr><tr><td>代码风格</td><td>显式类型 / 明确并发隔离 / 优先值类型 / 不使用 <code>@unchecked Sendable</code> / 不写 <code>force unwrap</code> 兜底</td></tr><tr><td>图解</td><td>每层至少 1 张机制图;关键篇补 SwiftUI 数据流、并发隔离域、SwiftData schema、签名链与发布管线图</td></tr><tr><td>验收</td><td>每篇末尾给出手动验证步骤;关键篇补 Swift Testing 或 UI Testing 脚本化检查</td></tr><tr><td>官方指针</td><td>标注核心类名与所属 framework,如 <code>NavigationStack</code> (SwiftUI)、<code>ModelContainer</code> (SwiftData)、<code>UNUserNotificationCenter</code> (UserNotifications)、<code>BGTaskScheduler</code> (BackgroundTasks)、<code>AVCaptureSession</code> (AVFoundation)</td></tr><tr><td>版本标注</td><td>涉及 iOS 19+ 新 API 单独标注「iOS 19+」并给 iOS 18 降级方案;涉及 Swift 6.x minor 差异时标注最低 toolchain</td></tr></tbody></table><hr><h2 id="章节节奏" tabindex="-1">章节节奏 <a class="header-anchor" href="#章节节奏" aria-label="Permalink to &quot;章节节奏&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-05 建心智:理解 Swift 6 类型系统、Concurrency、actor/Sendable 与 Xcode 16 项目骨架</span></span>
<span class="line"><span>06-10 做 UI:SwiftUI View、@Observable、@Binding/@Environment、布局与 Modifier</span></span>
<span class="line"><span>11-13 做交互:动画/转场/共享元素 + Gesture 组合与冲突 + NavigationStack 类型化路由</span></span>
<span class="line"><span>14-16 做闭环:SwiftData 全景 + URLSession async + Keychain / CryptoKit / App Group</span></span>
<span class="line"><span>17-21 做能力:UIKit/OC 互操作 + 推送 + AVFoundation/PhotoKit + 权限/Privacy Manifest + 后台/App Intents</span></span>
<span class="line"><span>22-25 做平台特色:Widget / Live Activities / Dynamic Island + StoreKit 2 / Sign in with Apple + Accessibility / 国际化 + Core ML / Vision</span></span>
<span class="line"><span>26-30 做发布:SwiftUI 性能 + Instruments/MetricKit + SPM/Build System + Swift Testing/UI Test + TestFlight/审核/多平台延伸</span></span></code></pre></div>`,55)])])}const u=t(c,[["render",n]]);export{S as __pageData,u as default};
